INSERT INTO public.posts (slug, title, excerpt, cover_url, content, tags, published, published_at) VALUES
(
  'ejare-ps5-vs-kharid',
  'اجاره پلی استیشن ۵ یا خرید؟ راهنمای کامل مقایسه هزینه',
  'مقایسه اقتصادی اجاره PS5 در برابر خرید کنسول جدید یا دست‌دوم — به همراه محاسبه هزینه ماهانه، ریسک گارانتی و انتخاب بازی.',
  '/assets/images/home/dashboard.webp',
  '<h2>چرا این تصمیم مهم است؟</h2><p>قیمت پلی استیشن ۵ در ایران به‌خاطر نوسان ارز و هزینه واردات، هم‌سنگ چند ماه اجاره کنسول است. قبل از خرید، بهتر است پاسخ چند سؤال ساده را بدانید: چند ساعت در هفته بازی می‌کنید؟ چند بازی در سال تمام می‌کنید؟ آیا به نسخه جدید بازی‌ها نیاز دارید یا کاتالوگ متنوع مهم‌تر است؟</p><h2>هزینه واقعی خرید PS5</h2><p>خرید یک PS5 نو به‌همراه یک دسته اضافی و دو بازی اورجینال، در بازار امروز ایران رقمی قابل‌توجه است. به این عدد باید هزینه تعمیرات احتمالی، نگهداری و به‌روزرسانی سالانه کاتالوگ بازی را هم اضافه کرد.</p><h2>هزینه اجاره ماهانه از گیمیو</h2><p>در پلن‌های اجاره گیمیو، شما با پرداخت ماهانه مشخص، کنسول را همراه دسته، کابل و چند بازی محبوب تحویل می‌گیرید. سرویس و پشتیبانی روی دوش ماست و در پایان دوره، می‌توانید مدل را ارتقا دهید یا کنسول را بازگردانید.</p><h2>چه کسانی باید اجاره کنند؟</h2><ul><li>کاربرانی که کمتر از ۱۰ ساعت در هفته بازی می‌کنند.</li><li>خانواده‌هایی که می‌خواهند در تعطیلات یا مهمانی‌ها کنسول داشته باشند.</li><li>گیمرهایی که دوست دارند قبل از خرید، مدل‌های مختلف را تجربه کنند.</li></ul><h2>چه کسانی باید بخرند؟</h2><p>اگر بیش از ۲۰ ساعت در هفته بازی می‌کنید، به بازی‌های آنلاین رقابتی وابسته‌اید و بودجه اولیه برایتان مسئله نیست، خرید در بلندمدت صرفه بیشتری دارد.</p><h2>جمع‌بندی</h2><p>اجاره برای اکثر کاربران ایرانی گزینه هوشمندانه‌تری است، چون ریسک قیمت، تعمیر و انتخاب بازی را کاهش می‌دهد. برای مشاهده پلن‌ها به صفحه <a href="/pricing">قیمت‌گذاری</a> سر بزنید.</p>',
  ARRAY['اجاره پلی استیشن','PS5','مقایسه','راهنمای خرید'],
  true,
  now() - interval '20 days'
),
(
  'behtarin-baziha-ps5-2026',
  'بهترین بازی‌های پلی استیشن ۵ در سال ۲۰۲۶ برای اجاره',
  'فهرست منتخب بهترین بازی‌های انحصاری و چندسکویی PS5 که در سبد اجاره گیمیو موجودند — از اکشن ماجراجویی تا ورزشی و خانوادگی.',
  '/assets/images/home/dashboard.webp',
  '<h2>چرا انتخاب بازی مهم است؟</h2><p>وقتی کنسول را اجاره می‌کنید، وقت شما محدود است و می‌خواهید بهترین تجربه ممکن را داشته باشید. این فهرست بر اساس امتیاز منتقدان، محبوبیت میان کاربران گیمیو و تنوع سبک تهیه شده است.</p><h2>۱. Marvel''s Spider-Man 2</h2><p>یکی از بهترین انحصاری‌های سونی که گرافیک و گیم‌پلی روان آن، قدرت PS5 را به رخ می‌کشد. مناسب همه سنین.</p><h2>۲. God of War Ragnarok</h2><p>ادامه ماجراجویی کریتوس و آترئوس؛ داستان قوی، مبارزات نفس‌گیر و دنیایی وسیع.</p><h2>۳. EA Sports FC 24</h2><p>انتخاب اول علاقه‌مندان فوتبال. حالت Ultimate Team و بازی آنلاین با دوستان.</p><h2>۴. Gran Turismo 7</h2><p>شبیه‌ساز اتومبیل‌رانی با گرافیک خیره‌کننده و پشتیبانی از فرمان.</p><h2>۵. Hogwarts Legacy</h2><p>ماجراجویی در دنیای هری پاتر — گزینه محبوب خانواده‌ها.</p><h2>۶. Elden Ring</h2><p>برای گیمرهای حرفه‌ای که چالش سخت را دوست دارند.</p><h2>چطور بازی‌ها را در گیمیو انتخاب کنیم؟</h2><p>هنگام ثبت سفارش اجاره، می‌توانید تا چند عنوان از سبد بازی‌های ما انتخاب کنید. لیست کامل در صفحه <a href="/consoles">کنسول‌ها</a> قابل مشاهده است.</p>',
  ARRAY['بازی PS5','معرفی بازی','بهترین بازی‌ها','2026'],
  true,
  now() - interval '15 days'
),
(
  'rahnama-tanzim-ps5',
  'راهنمای گام‌به‌گام راه‌اندازی PS5 پس از تحویل',
  'از اتصال کابل‌ها تا ورود به حساب، ساخت پروفایل و دانلود اولین بازی — راهنمای کامل نصب PS5 برای مبتدی‌ها.',
  '/assets/images/home/dashboard.webp',
  '<h2>پیش از شروع</h2><p>هنگام تحویل کنسول از گیمیو، جعبه شامل PS5، یک دسته DualSense، کابل HDMI، کابل برق و کابل USB-C است. قبل از شروع، تلویزیون HDMI 2.1 یا حداقل 2.0 آماده کنید.</p><h2>مرحله ۱: اتصال کابل‌ها</h2><p>کابل HDMI را به پورت HDMI OUT کنسول و ورودی تلویزیون وصل کنید. سپس کابل برق را متصل کنید و دسته را با کابل USB به کنسول بزنید تا شارژ شود.</p><h2>مرحله ۲: روشن کردن و انتخاب زبان</h2><p>دکمه پاور را فشار دهید. زبان و منطقه را انتخاب کنید (پیشنهاد ما English برای سازگاری با اکثر بازی‌ها).</p><h2>مرحله ۳: اتصال به اینترنت</h2><p>Wi-Fi خانگی را انتخاب و رمز را وارد کنید. برای بازی آنلاین، اتصال کابلی پایدارتر است.</p><h2>مرحله ۴: ورود یا ساخت PSN</h2><p>در صورت داشتن حساب PlayStation Network وارد شوید. اگر ندارید، می‌توانید یک حساب رایگان بسازید. تیم پشتیبانی گیمیو در این مرحله همراه شماست.</p><h2>مرحله ۵: دانلود بازی‌ها</h2><p>بازی‌های انتخابی شما در کتابخانه حساب قرار داده شده‌اند. کافی است روی آیکون بازی، Download را بزنید.</p><h2>نکات نگهداری</h2><ul><li>کنسول را در فضای باز و با تهویه مناسب قرار دهید.</li><li>هر ماه یک بار سطح دستگاه را از گرد و غبار پاک کنید.</li><li>در صورت هرگونه ایراد، فوراً با پشتیبانی گیمیو تماس بگیرید.</li></ul>',
  ARRAY['راهنمای PS5','آموزش','نصب کنسول'],
  true,
  now() - interval '10 days'
),
(
  'ps5-vs-xbox-series-x',
  'PS5 در برابر Xbox Series X: کدام کنسول را اجاره کنیم؟',
  'مقایسه فنی و کاربردی پلی استیشن ۵ و ایکس‌باکس سری X از نظر عملکرد، بازی‌های انحصاری، قیمت اجاره و اکوسیستم.',
  '/assets/images/home/dashboard.webp',
  '<h2>مقدمه</h2><p>هر دو کنسول نسل نهم، قدرتمند و مدرن هستند. تفاوت اصلی در بازی‌های انحصاری، تجربه کاربری و سرویس‌های اشتراکی است.</p><h2>سخت‌افزار</h2><p>Xbox Series X با ۱۲ ترافلاپس، از نظر خام قدرتمندتر است اما PS5 با SSD اختصاصی و معماری I/O سریع، در بارگذاری بازی‌ها برتری دارد.</p><h2>بازی‌های انحصاری</h2><ul><li><strong>PS5:</strong> Spider-Man 2، God of War، The Last of Us، Gran Turismo، Demon''s Souls.</li><li><strong>Xbox:</strong> Forza Motorsport، Halo Infinite، Starfield، Sea of Thieves.</li></ul><h2>سرویس‌های اشتراکی</h2><p>Xbox Game Pass Ultimate یکی از بهترین ارزش‌ها در دنیای گیمینگ است. PlayStation Plus هم پلن‌های Extra و Premium خوبی دارد.</p><h2>دسته و تجربه کاربری</h2><p>DualSense پلی استیشن با هپتیک فیدبک و ماشه‌های تطبیقی، تجربه بازی را متفاوت می‌کند. دسته Xbox ارگونومی سنتی‌تر و باتری قابل تعویض دارد.</p><h2>اجاره از گیمیو</h2><p>هر دو کنسول در سبد اجاره گیمیو موجودند. برای مشاهده تعرفه‌ها به <a href="/pricing">قیمت‌گذاری</a> مراجعه کنید.</p><h2>پیشنهاد نهایی</h2><p>اگر عاشق داستان‌های سینمایی هستید، PS5 انتخاب بهتر است. اگر Game Pass و بازی چندسکویی برایتان مهم است، Xbox Series X را اجاره کنید.</p>',
  ARRAY['PS5','Xbox','مقایسه','کنسول'],
  true,
  now() - interval '5 days'
),
(
  'ejare-konsol-mehmani',
  'اجاره کنسول برای مهمانی و تعطیلات: چه پلنی مناسب است؟',
  'می‌خواهید در مهمانی خانوادگی یا تعطیلات نوروز، یک شب یا یک هفته کنسول داشته باشید؟ راهنمای انتخاب پلن کوتاه‌مدت گیمیو.',
  '/assets/images/home/dashboard.webp',
  '<h2>چرا اجاره کوتاه‌مدت؟</h2><p>خرید کنسول برای چند روز مهمانی منطقی نیست. اجاره کوتاه‌مدت گیمیو، کنسول را همراه بازی‌های خانوادگی و دو دسته درب منزل شما تحویل می‌دهد.</p><h2>بهترین بازی‌ها برای مهمانی</h2><ul><li>FIFA / EA Sports FC — رقابت دو نفره یا چهار نفره.</li><li>It Takes Two — بازی همکاری دو نفره برای زوج‌ها.</li><li>Overcooked 2 — چهار نفره، پر از خنده.</li><li>Mortal Kombat — کلاسیک مهمانی‌های ایرانی.</li></ul><h2>بسته پیشنهادی</h2><p>پلن ۳ روزه یا هفتگی گیمیو شامل PS5 + دو دسته + چهار بازی منتخب مهمانی است. تحویل و جمع‌آوری در تهران رایگان.</p><h2>سفارش سریع</h2><p>در صفحه <a href="/pricing">قیمت‌گذاری</a> پلن کوتاه‌مدت را انتخاب کنید یا با پشتیبانی از طریق <a href="/contact">تماس</a> بگیرید. حداقل ۴۸ ساعت قبل از مهمانی سفارش دهید تا رزرو مطمئن باشد.</p><h2>نکات مهم</h2><ul><li>هزینه ودیعه در پایان دوره کامل بازگردانده می‌شود.</li><li>در طول اجاره، پشتیبانی ۲۴ ساعته در دسترس است.</li><li>امکان تمدید تلفنی یا آنلاین وجود دارد.</li></ul>',
  ARRAY['اجاره کوتاه‌مدت','مهمانی','نوروز','خانواده'],
  true,
  now() - interval '2 days'
);